import "../quiz_question.dart";

const _subject = "Commerce";

QuizQuestion _q(String subject, String text, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: subject,
    text: text,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

QuizQuestion _cq(String text, List<String> options, String correct, String explanation) =>
    _q(_subject, text, options, correct, explanation);

